using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ───────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 9.99m);

        Assert.AreEqual(9.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 3, price: 10.00m);

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_QuantityGreaterThanOne_MultipliesPrice()
    {
        _cart.AddItem("SKU-001", quantity: 5, price: 3.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_Throws()
    {
        _cart.AddItem("SKU-001", quantity: 0, price: 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativeQuantity_Throws()
    {
        _cart.AddItem("SKU-001", quantity: -1, price: 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_Throws()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: -5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_Throws()
    {
        _cart.AddItem(null!, quantity: 1, price: 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_Throws()
    {
        _cart.AddItem("", quantity: 1, price: 10.00m);
    }

    // ── RemoveItem ────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_OnlyRemovesThatItem()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 20.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentSku_Throws()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    public void RemoveItem_ThenReAddSameItem_WorksCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.RemoveItem("SKU-001");
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── CalculateTotal ────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_FractionalPrices_HandlesDecimalsCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 1.33m);

        Assert.AreEqual(3.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAllItemsRemoved_ReturnsZero()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ───────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be less than the original price after applying a coupon.");
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        _cart.ApplyCoupon("BOGUS");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_NullCode_Throws()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        _cart.ApplyCoupon("");
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverGoesBelowZero()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 1.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() >= 0m,
            "Total should never be negative after applying a coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── Combined workflows ────────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCoupon_ProducesExpectedTotal()
    {
        _cart.AddItem("SKU-A", quantity: 2, price: 25.00m);
        _cart.AddItem("SKU-B", quantity: 1, price: 50.00m);
        _cart.RemoveItem("SKU-B");
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();

        Assert.IsTrue(total > 0m && total < 50.00m,
            $"Expected a discounted total under 50.00 but got {total}.");
    }
}

